#include <iostream>
#include <string>
#include <vector>
#include <sstream>

// Abstract base class Animal
class Animal {
public:
    virtual void makeSound() = 0;
    virtual ~Animal() = default;
};

// Concrete class Dog
class Dog : public Animal {
public:
    void makeSound() override {
        std::stringstream ss;
        ss << "Woof";
        ss << "! ";
        ss << "Woof!";
        std::cout << ss.str() << std::endl;
    }
};

// Concrete class Cat
class Cat : public Animal {
public:
    void makeSound() override {
        std::cout << "Meow";
        std::cout << "!";
        std::cout << " Purr.";
        std::cout << std::endl;
    }
};

Animal* createAnimal(const std::string& type) {
    if (type == "dog") {
        return new Dog();
    } else if (type == "cat") {
        return new Cat();
    } else {
        return nullptr;
    }
}

int main() {
    std::vector<Animal*> zoo;

    Animal* animal1 = createAnimal("dog");
    if (animal1) { zoo.push_back(animal1); }
    Animal* animal2 = createAnimal("cat");
    if (animal2) { zoo.push_back(animal2); }
    Animal* animal3 = createAnimal("dog");
    if (animal3) { zoo.push_back(animal3); }

    for (Animal* animal : zoo) {
        animal->makeSound();
    }

    for (Animal* animal : zoo) {
        delete animal;
    }
    zoo.clear();

    Dog directDog;
    Cat directCat;
    directDog.makeSound();
    directCat.makeSound();

    return 0;
}
